--
-- Name: calc_price_per_pax(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.calc_price_per_pax() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
            BEGIN
                IF NEW.expected_pax > 0 THEN
                    NEW.price_per_pax = ROUND(NEW.total_revenue / NEW.expected_pax, 2);
                ELSE
                    NEW.price_per_pax = 0;
                END IF;
                RETURN NEW;
            END;
            $$;


